# Category: mfa_bypass

from flask import Flask, request, session, redirect, url_for, render_template_string, jsonify
from werkzeug.security import generate_password_hash, check_password_hash
import pyotp
import secrets
from functools import wraps

app = Flask(__name__)
app.secret_key = secrets.token_hex(32)

users = {
    "alice": {
        "password_hash": generate_password_hash("password123"),
        "mfa_enabled": True,
        "otp_secret": pyotp.random_base32(),
    },
    "bob": {
        "password_hash": generate_password_hash("password456"),
        "mfa_enabled": False,
        "otp_secret": None,
    },
}

LOGIN_TEMPLATE = """
<!doctype html>
<title>Login</title>
<h2>Login</h2>
<form method="post">
  <label>Username</label><br>
  <input type="text" name="username" required><br><br>
  <label>Password</label><br>
  <input type="password" name="password" required><br><br>
  <button type="submit">Login</button>
</form>
<p style="color:red;">{{ error }}</p>
"""

OTP_TEMPLATE = """
<!doctype html>
<title>OTP Verification</title>
<h2>Enter OTP</h2>
<form method="post">
  <label>One-Time Password</label><br>
  <input type="text" name="otp" required><br><br>
  <button type="submit">Verify</button>
</form>
<p style="color:red;">{{ error }}</p>
"""

HOME_TEMPLATE = """
<!doctype html>
<title>Home</title>
<h2>Welcome, {{ username }}</h2>
<p>Authenticated successfully.</p>
<p>MFA satisfied: {{ mfa_verified }}</p>
<a href="{{ url_for('logout') }}">Logout</a>
"""

def get_user(username):
    return users.get(username)

def login_required(view):
    @wraps(view)
    def wrapped(*args, **kwargs):
        if not session.get("authenticated"):
            return redirect(url_for("login"))
        return view(*args, **kwargs)
    return wrapped

@app.route("/")
@login_required
def home():
    return render_template_string(
        HOME_TEMPLATE,
        username=session.get("username"),
        mfa_verified=session.get("mfa_verified", False),
    )

@app.route("/login", methods=["GET", "POST"])
def login():
    error = ""
    if request.method == "POST":
        username = request.form.get("username", "").strip()
        password = request.form.get("password", "")
        user = get_user(username)

        if not user or not check_password_hash(user["password_hash"], password):
            error = "Invalid username or password"
            return render_template_string(LOGIN_TEMPLATE, error=error), 401

        session.clear()
        session["preauth_user"] = username

        if user["mfa_enabled"]:
            session["mfa_required"] = True
            session["mfa_verified"] = False
            return redirect(url_for("verify_otp"))
        else:
            session["username"] = username
            session["authenticated"] = True
            session["mfa_required"] = False
            session["mfa_verified"] = True
            session.pop("preauth_user", None)
            return redirect(url_for("home"))

    return render_template_string(LOGIN_TEMPLATE, error=error)

@app.route("/verify-otp", methods=["GET", "POST"])
def verify_otp():
    if not session.get("mfa_required") or not session.get("preauth_user"):
        return redirect(url_for("login"))

    error = ""
    username = session["preauth_user"]
    user = get_user(username)

    if not user or not user["mfa_enabled"] or not user["otp_secret"]:
        session.clear()
        return redirect(url_for("login"))

    if request.method == "POST":
        otp = request.form.get("otp", "").strip()
        totp = pyotp.TOTP(user["otp_secret"])

        if totp.verify(otp, valid_window=1):
            session["username"] = username
            session["authenticated"] = True
            session["mfa_verified"] = True
            session["mfa_required"] = False
            session.pop("preauth_user", None)
            return redirect(url_for("home"))
        else:
            error = "Invalid OTP"
            return render_template_string(OTP_TEMPLATE, error=error), 401

    return render_template_string(OTP_TEMPLATE, error=error)

@app.route("/logout")
def logout():
    session.clear()
    return redirect(url_for("login"))

@app.route("/api/direct-login", methods=["POST"])
def api_direct_login():
    data = request.get_json(silent=True) or {}
    username = data.get("username", "").strip()
    password = data.get("password", "")

    user = get_user(username)
    if not user or not check_password_hash(user["password_hash"], password):
        return jsonify({"success": False, "error": "Invalid username or password"}), 401

    token = secrets.token_urlsafe(32)
    return jsonify({
        "success": True,
        "message": "Authenticated successfully via direct API login",
        "username": username,
        "mfa_skipped": True,
        "token": token,
    }), 200

@app.route("/api/login", methods=["POST"])
def api_login():
    data = request.get_json(silent=True) or {}
    username = data.get("username", "").strip()
    password = data.get("password", "")
    otp = data.get("otp", "").strip()

    user = get_user(username)
    if not user or not check_password_hash(user["password_hash"], password):
        return jsonify({"success": False, "error": "Invalid username or password"}), 401

    if user["mfa_enabled"]:
        if not otp:
            return jsonify({
                "success": False,
                "mfa_required": True,
                "error": "OTP required"
            }), 401

        totp = pyotp.TOTP(user["otp_secret"])
        if not totp.verify(otp, valid_window=1):
            return jsonify({"success": False, "mfa_required": True, "error": "Invalid OTP"}), 401

    token = secrets.token_urlsafe(32)
    return jsonify({
        "success": True,
        "username": username,
        "mfa_required": user["mfa_enabled"],
        "token": token,
    }), 200

